package main

import "fmt"

func describe(v any) {
    fmt.Printf("(%T) %v\n", v, v)
}

func main() {
    describe(42)
    describe("hello")
    describe(3.14)
    describe([]int{1, 2, 3})

    // Mixed slice
    mixed := []any{1, "two", 3.0, true}
    for _, v := range mixed {
        describe(v)
    }
}
